package com.bank.service;

import com.bank.model.BankingTransaction;
import com.bank.model.TransactionRequest;
import com.bank.model.TransactionResponse;
import com.bank.security.SecurityValidator;

import javax.annotation.Resource;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.math.BigDecimal;
import java.util.Date;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    targetNamespace = "http://bank.com/banking",
    endpointInterface = "com.bank.service.BankingService"
)
public class BankingServiceImpl implements BankingService {

    private static final Logger logger = Logger.getLogger(BankingServiceImpl.class.getName());
    private static final Map<String, BankingTransaction> transactionStore = new ConcurrentHashMap<>();
    private static final Map<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();

    @Resource
    private WebServiceContext wsContext;

    static {
        accountBalances.put("ACC001", new BigDecimal("10000.00"));
        accountBalances.put("ACC002", new BigDecimal("5000.00"));
        accountBalances.put("ACC003", new BigDecimal("15000.00"));
    }

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        try {
            logger.info("Processing transaction request");

            if (!validateRequest(request)) {
                return new TransactionResponse(false, null, "Invalid transaction request", null);
            }

            String fromAccount = sanitizeInput(request.getFromAccount());
            String toAccount = sanitizeInput(request.getToAccount());
            BigDecimal amount = request.getAmount();

            if (amount.compareTo(BigDecimal.ZERO) <= 0) {
                return new TransactionResponse(false, null, "Invalid amount", null);
            }

            BigDecimal fromBalance = accountBalances.getOrDefault(fromAccount, BigDecimal.ZERO);
            if (fromBalance.compareTo(amount) < 0) {
                return new TransactionResponse(false, null, "Insufficient funds", null);
            }

            String transactionId = UUID.randomUUID().toString();
            BankingTransaction transaction = new BankingTransaction(
                transactionId,
                fromAccount,
                toAccount,
                amount,
                sanitizeInput(request.getCurrency()),
                new Date(),
                "COMPLETED",
                sanitizeInput(request.getDescription())
            );

            accountBalances.put(fromAccount, fromBalance.subtract(amount));
            BigDecimal toBalance = accountBalances.getOrDefault(toAccount, BigDecimal.ZERO);
            accountBalances.put(toAccount, toBalance.add(amount));

            transactionStore.put(transactionId, transaction);

            logger.info("Transaction completed successfully: " + transactionId);
            return new TransactionResponse(true, transactionId, "Transaction successful", transaction);

        } catch (Exception e) {
            logger.severe("Error processing transaction: " + e.getMessage());
            return new TransactionResponse(false, null, "Transaction failed: " + e.getMessage(), null);
        }
    }

    @Override
    public BankingTransaction getTransactionStatus(String transactionId) {
        String sanitizedId = sanitizeInput(transactionId);
        return transactionStore.get(sanitizedId);
    }

    @Override
    public String getAccountBalance(String accountNumber) {
        String sanitizedAccount = sanitizeInput(accountNumber);
        BigDecimal balance = accountBalances.getOrDefault(sanitizedAccount, BigDecimal.ZERO);
        return balance.toString();
    }

    private boolean validateRequest(TransactionRequest request) {
        if (request == null) {
            return false;
        }
        if (request.getFromAccount() == null || request.getFromAccount().trim().isEmpty()) {
            return false;
        }
        if (request.getToAccount() == null || request.getToAccount().trim().isEmpty()) {
            return false;
        }
        if (request.getAmount() == null) {
            return false;
        }
        if (request.getCurrency() == null || request.getCurrency().trim().isEmpty()) {
            return false;
        }
        return true;
    }

    private String sanitizeInput(String input) {
        if (input == null) {
            return null;
        }
        return input.replaceAll("[^a-zA-Z0-9\\s\\-_.]", "").trim();
    }
}

