package com.bank.security;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.security.Key;
import java.security.KeyStore;
import java.security.PublicKey;
import java.security.cert.X509Certificate;
import java.util.Iterator;
import java.util.logging.Logger;

public class SecurityValidator {

    private static final Logger logger = Logger.getLogger(SecurityValidator.class.getName());
    private static final String SIGNATURE_NS = "http://www.w3.org/2000/09/xmldsig#";

    public static boolean validateSignature(byte[] soapMessage, KeyStore trustStore) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);

            DocumentBuilder builder = dbf.newDocumentBuilder();
            Document doc = builder.parse(new ByteArrayInputStream(soapMessage));

            NodeList signatureNodes = doc.getElementsByTagNameNS(SIGNATURE_NS, "Signature");
            if (signatureNodes.getLength() == 0) {
                logger.warning("No signature found in SOAP message");
                return false;
            }

            Element signatureElement = (Element) signatureNodes.item(0);

            XMLSignatureFactory fac = XMLSignatureFactory.getInstance("DOM");
            DOMValidateContext valContext = new DOMValidateContext(new KeyValueKeySelector(), signatureElement);

            XMLSignature signature = fac.unmarshalXMLSignature(valContext);

            PublicKey publicKey = extractPublicKey(signature, trustStore);
            if (publicKey == null) {
                logger.warning("Could not extract public key from signature");
                return false;
            }

            valContext = new DOMValidateContext(publicKey, signatureElement);
            boolean isValid = signature.validate(valContext);

            if (isValid) {
                logger.info("Signature validation successful");
            } else {
                logger.warning("Signature validation failed");
            }

            return isValid;

        } catch (Exception e) {
            logger.severe("Error validating signature: " + e.getMessage());
            return false;
        }
    }

    private static PublicKey extractPublicKey(XMLSignature signature, KeyStore trustStore) {
        try {
            KeyInfo keyInfo = signature.getKeyInfo();
            if (keyInfo == null) {
                return null;
            }

            Iterator<?> iter = keyInfo.getContent().iterator();
            while (iter.hasNext()) {
                Object content = iter.next();
                if (content instanceof X509Data) {
                    X509Data x509Data = (X509Data) content;
                    Iterator<?> x509Iter = x509Data.getContent().iterator();
                    while (x509Iter.hasNext()) {
                        Object x509Content = x509Iter.next();
                        if (x509Content instanceof X509Certificate) {
                            X509Certificate cert = (X509Certificate) x509Content;
                            return cert.getPublicKey();
                        }
                    }
                }
            }
        } catch (Exception e) {
            logger.severe("Error extracting public key: " + e.getMessage());
        }
        return null;
    }

    private static class KeyValueKeySelector extends javax.xml.crypto.KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose, 
                                       AlgorithmMethod method, XMLCryptoContext context) {
            if (keyInfo == null) {
                throw new IllegalArgumentException("KeyInfo is null");
            }

            Iterator<?> iter = keyInfo.getContent().iterator();
            while (iter.hasNext()) {
                Object content = iter.next();
                if (content instanceof X509Data) {
                    X509Data x509Data = (X509Data) content;
                    Iterator<?> x509Iter = x509Data.getContent().iterator();
                    while (x509Iter.hasNext()) {
                        Object x509Content = x509Iter.next();
                        if (x509Content instanceof X509Certificate) {
                            final PublicKey key = ((X509Certificate) x509Content).getPublicKey();
                            return new KeySelectorResult() {
                                public Key getKey() {
                                    return key;
                                }
                            };
                        }
                    }
                }
            }
            throw new IllegalArgumentException("No key found");
        }
    }

    public static String extractSignedElement(Document doc, String elementName) {
        try {
            NodeList nodes = doc.getElementsByTagName(elementName);
            if (nodes.getLength() > 0) {
                Element element = (Element) nodes.item(0);
                return element.getTextContent();
            }
        } catch (Exception e) {
            logger.severe("Error extracting signed element: " + e.getMessage());
        }
        return null;
    }
}

// SignatureHandler.java
package com.bank.security;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.io.ByteArrayOutputStream;
import java.security.KeyStore;
import java.util.Set;
import java.util.logging.Logger;

public class SignatureHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger logger = Logger.getLogger(SignatureHandler.class.getName());
    private KeyStore trustStore;

    public SignatureHandler(KeyStore trustStore) {
        this.trustStore = trustStore;
    }

    @Override
    public Set<QName> getHeaders() {
        return null;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outboundProperty = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (outboundProperty == null || !outboundProperty) {
            try {
                SOAPMessage message = context.getMessage();
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                message.writeTo(baos);
                byte[] messageBytes = baos.toByteArray();

                boolean isValid = SecurityValidator.validateSignature(messageBytes, trustStore);

                if (!isValid) {
                    logger.severe("Signature validation failed - rejecting message");
                    throw new SecurityException("Invalid signature");
                }

                logger.info("Signature validation successful");

            } catch (Exception e) {
                logger.severe("Error handling message: " + e.getMessage());
                throw new RuntimeException("Security validation failed", e);
            }
        }

        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }
}

// KeyStoreManager.java
package com.bank.security;

import java.io.FileInputStream;
import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.Certificate;
import java.util.logging.Logger;

public class KeyStoreManager {

    private static final Logger logger = Logger.getLogger(KeyStoreManager.class.getName());

    public static KeyStore loadKeyStore(String keystorePath, String password) {
        try (InputStream is = new FileInputStream(keystorePath)) {
            KeyStore keyStore = KeyStore.getInstance("JKS");
            keyStore.load(is, password.toCharArray());
            return keyStore;
        } catch (Exception e) {
            logger.severe("Error loading keystore: " + e.getMessage());
            throw new RuntimeException("Failed to load keystore", e);
        }
    }

    public static PrivateKey getPrivateKey(KeyStore keyStore, String alias, String password) {
        try {
            return (PrivateKey) keyStore.getKey(alias, password.toCharArray());
        } catch (Exception e) {
            logger.severe("Error getting private key: " + e.getMessage());
            throw new RuntimeException("Failed to get private key", e);
        }
    }

    public static Certificate getCertificate(KeyStore keyStore, String alias) {
        try {
            return keyStore.getCertificate(alias);
        } catch (Exception e) {
            logger.severe("Error getting certificate: " + e.getMessage());
            throw new RuntimeException("Failed to get certificate", e);
        }
    }
}

